class Solution:
  def modify_pipeline(self, pipeline: list) -> list:
    modified_pipeline = []
    for stage in pipeline:
      if stage['type'] == 'project':
        stage['spec']['includeNested'] = True
      modified_pipeline.append(stage)
    return modified_pipeline
